| MCP:lFtNSt | #!/usr/bin/env bash
| MCP:lFtNSt | set -euo pipefail
| MCP:lFtNSt | TARGET=${1:-http://host.docker.internal:8080}
| MCP:lFtNSt | case "$TARGET" in
| MCP:lFtNSt |   http://127.0.0.1:*|http://localhost:*|http://host.docker.internal:*) ;;
| MCP:lFtNSt |   *) echo "Refusing non-local target: $TARGET" >&2; exit 2 ;;
| MCP:lFtNSt | esac
| MCP:lFtNSt | docker run --rm -t -v "$(pwd):/zap/wrk" ghcr.io/zaproxy/zaproxy:stable zap-baseline.py -t "$TARGET" -c zap/baseline.conf -J reports/zap_baseline.json || true
